#!/usr/bin/env python3

from __future__ import annotations

import argparse
import csv
import statistics
import sys
from collections import defaultdict
from pathlib import Path

import matplotlib.pyplot as plt


def parse_args() -> argparse.Namespace:
    repo_root = Path(__file__).resolve().parent.parent
    default_input = repo_root / "build" / "leveldb_benchmark_sharded_sweep.csv"
    default_output = repo_root / "build" / "leveldb_benchmark_sharded_sweep.png"

    parser = argparse.ArgumentParser(
        description=(
            "Plot benchmark sweep CSV generated by "
            "run_leveldb_benchmark_sharded_sweep.sh"
        )
    )
    parser.add_argument(
        "--input",
        type=Path,
        default=default_input,
        help=f"Input CSV path (default: {default_input})",
    )
    parser.add_argument(
        "--output",
        type=Path,
        default=default_output,
        help=f"Output image path (default: {default_output})",
    )
    parser.add_argument(
        "--aggregate",
        choices=("mean", "median"),
        default="mean",
        help="How to aggregate repetitions for each configuration",
    )
    parser.add_argument(
        "--no-error-band",
        action="store_true",
        help="Disable the +/- one standard deviation band around each line",
    )
    parser.add_argument(
        "--no-error-bars",
        action="store_true",
        help="Disable capped +/- one standard deviation error bars around each point",
    )
    parser.add_argument(
        "--log2-x",
        action="store_true",
        help="Use a base-2 logarithmic x-axis for threads",
    )
    parser.add_argument(
        "--title",
        default="LevelDB sharded benchmark sweep",
        help="Figure title",
    )
    return parser.parse_args()


def load_rows(csv_path: Path) -> list[dict[str, object]]:
    if not csv_path.is_file():
        raise FileNotFoundError(f"CSV file not found: {csv_path}")

    rows: list[dict[str, object]] = []
    with csv_path.open(newline="", encoding="utf-8") as handle:
        reader = csv.DictReader(handle)
        required_columns = {
            "pmem_shards",
            "threads",
            "benchmark_shards",
            "benchmark",
            "repetition",
            "micros_per_op",
        }
        if reader.fieldnames is None:
            raise ValueError(f"CSV file has no header: {csv_path}")
        missing = required_columns.difference(reader.fieldnames)
        if missing:
            missing_list = ", ".join(sorted(missing))
            raise ValueError(f"CSV file is missing columns: {missing_list}")

        for line_number, row in enumerate(reader, start=2):
            try:
                rows.append(
                    {
                        "pmem_shards": int(row["pmem_shards"]),
                        "threads": int(row["threads"]),
                        "benchmark_shards": int(row["benchmark_shards"]),
                        "benchmark": row["benchmark"],
                        "repetition": int(row["repetition"]),
                        "micros_per_op": float(row["micros_per_op"]),
                    }
                )
            except (TypeError, ValueError) as exc:
                raise ValueError(
                    f"Could not parse CSV row {line_number} in {csv_path}: {exc}"
                ) from exc

    if not rows:
        raise ValueError(f"CSV file is empty: {csv_path}")
    return rows


def aggregate_rows(
    rows: list[dict[str, object]], aggregate: str
) -> dict[tuple[str, int, int], list[tuple[int, float, float]]]:
    grouped: dict[tuple[str, int, int, int], list[float]] = defaultdict(list)
    for row in rows:
        grouped[
            (
                str(row["benchmark"]),
                int(row["pmem_shards"]),
                int(row["threads"]),
                int(row["benchmark_shards"]),
            )
        ].append(float(row["micros_per_op"]))

    aggregated: dict[tuple[str, int, int], list[tuple[int, float, float]]] = defaultdict(list)
    for (benchmark, pmem_shards, threads, benchmark_shards), samples in sorted(grouped.items()):
        center = (
            statistics.mean(samples)
            if aggregate == "mean"
            else statistics.median(samples)
        )
        spread = statistics.stdev(samples) if len(samples) > 1 else 0.0
        aggregated[(benchmark, pmem_shards, benchmark_shards)].append(
            (threads, center, spread)
        )
    return aggregated


def plot_rows(
    aggregated: dict[tuple[str, int, int], list[tuple[int, float, float]]],
    output_path: Path,
    title: str,
    log2_x: bool,
    show_error_band: bool,
    show_error_bars: bool,
) -> None:
    benchmarks = sorted({key[0] for key in aggregated})
    pmem_values = sorted({key[1] for key in aggregated})
    benchmark_shard_values = sorted({key[2] for key in aggregated})

    rows = len(benchmarks)
    cols = len(pmem_values)
    fig_width = max(6 * cols, 8)
    fig_height = max(4 * rows, 4.5)
    figure, axes = plt.subplots(rows, cols, figsize=(fig_width, fig_height), squeeze=False)
    cmap = plt.get_cmap("viridis")
    color_positions = [
        index / max(len(benchmark_shard_values) - 1, 1)
        for index in range(len(benchmark_shard_values))
    ]
    color_map = {
        benchmark_shards: cmap(position)
        for benchmark_shards, position in zip(benchmark_shard_values, color_positions)
    }
    y_limits_by_benchmark: dict[str, tuple[float, float]] = {}

    for benchmark in benchmarks:
        y_min: float | None = None
        y_max: float | None = None
        for pmem_shards in pmem_values:
            for benchmark_shards in benchmark_shard_values:
                points = aggregated.get((benchmark, pmem_shards, benchmark_shards))
                if not points:
                    continue

                for _, center, spread in points:
                    lower = max(center - spread, 0.0) if show_error_band else center
                    upper = center + spread if show_error_band else center
                    y_min = lower if y_min is None else min(y_min, lower)
                    y_max = upper if y_max is None else max(y_max, upper)

        if y_min is None or y_max is None:
            continue

        if y_min == y_max:
            padding = max(y_max * 0.05, 1.0)
        else:
            padding = (y_max - y_min) * 0.05
        lower_limit = max(y_min - padding, 0.0)
        upper_limit = y_max + padding
        y_limits_by_benchmark[benchmark] = (lower_limit, upper_limit)

    for row_index, benchmark in enumerate(benchmarks):
        for col_index, pmem_shards in enumerate(pmem_values):
            axis = axes[row_index][col_index]
            plotted_any = False

            for benchmark_shards in benchmark_shard_values:
                points = aggregated.get((benchmark, pmem_shards, benchmark_shards))
                if not points:
                    continue

                plotted_any = True
                points = sorted(points, key=lambda point: point[0])
                x_values = [point[0] for point in points]
                y_values = [point[1] for point in points]
                y_spread = [point[2] for point in points]
                color = color_map[benchmark_shards]

                if show_error_bars:
                    axis.errorbar(
                        x_values,
                        y_values,
                        yerr=y_spread,
                        marker="o",
                        linewidth=1.8,
                        markersize=4,
                        label=f"benchmark_shards={benchmark_shards}",
                        color=color,
                        capsize=2.5,
                        elinewidth=0.8,
                        capthick=0.8,
                    )
                else:
                    axis.plot(
                        x_values,
                        y_values,
                        marker="o",
                        linewidth=1.8,
                        markersize=4,
                        label=f"benchmark_shards={benchmark_shards}",
                        color=color,
                    )
                if show_error_band:
                    lower = [max(value - spread, 0.0) for value, spread in zip(y_values, y_spread)]
                    upper = [value + spread for value, spread in zip(y_values, y_spread)]
                    axis.fill_between(x_values, lower, upper, color=color, alpha=0.12)

            axis.set_title(f"{benchmark} | pmem_shards={pmem_shards}")
            axis.set_xlabel("threads")
            axis.set_ylabel("micros/op")
            axis.grid(True, alpha=0.3)

            if log2_x:
                axis.set_xscale("log", base=2)

            y_limits = y_limits_by_benchmark.get(benchmark)
            if y_limits is not None:
                axis.set_ylim(*y_limits)

            if plotted_any:
                axis.legend(fontsize="small")
            else:
                axis.text(
                    0.5,
                    0.5,
                    "No data",
                    transform=axis.transAxes,
                    ha="center",
                    va="center",
                )

    figure.suptitle(title)
    figure.tight_layout(rect=(0, 0, 1, 0.97))
    output_path.parent.mkdir(parents=True, exist_ok=True)
    figure.savefig(output_path, dpi=200)
    plt.close(figure)


def main() -> int:
    args = parse_args()
    try:
        rows = load_rows(args.input)
        aggregated = aggregate_rows(rows, args.aggregate)
        plot_rows(
            aggregated=aggregated,
            output_path=args.output,
            title=args.title,
            log2_x=args.log2_x,
            show_error_band=not args.no_error_band,
            show_error_bars=not args.no_error_bars,
        )
    except (FileNotFoundError, ValueError) as exc:
        print(exc, file=sys.stderr)
        return 1
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
